@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label class="fw-semibold text-nowrap mb-0" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select" class="form-select form-select-sm" style="width: auto;"
            value="@WarehouseState.SelectedWarehouseId" @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in Services.WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(warehouseId))
        {
            WarehouseState.SetWarehouse(warehouseId);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChanged;
    }

    private void OnStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        WarehouseState.OnChange -= OnStateChanged;
    }
}

@rendermode InteractiveServer
@inject Services.InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        if (_handler is not null)
        {
            AlertService.OnAlertCountChanged -= _handler;
        }
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-4">
            <strong>@WarehouseState.SelectedWarehouseName</strong>
            <span class="text-muted">(@WarehouseState.SelectedWarehouseId)</span>
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Low Stock Alerts</h5>
        <div class="d-flex align-items-center gap-3">
            <span class="fs-1 fw-bold @(AlertService.LowStockCount > 5 ? "text-danger" : "text-warning")">
                @AlertService.LowStockCount
            </span>
            <span class="text-muted">items below minimum stock level</span>
        </div>
        <p class="text-muted mt-2 mb-0">
            <small>Auto-refreshes every 10 seconds</small>
        </p>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        AlertService.StartPolling();
    }

    public void Dispose()
    {
        AlertService.StopPolling();

        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;
        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

